            LastAccessedAt = DateTime.UtcNow;
        }

        public void AddToCart(CartItem item)
        {
            if (item == null)
                throw new ArgumentNullException(nameof(item));

            var existing = ShoppingCart.FirstOrDefault(i => i.ProductId == item.ProductId);
            if (existing != null)
            {
                existing.Quantity += item.Quantity;
            }
            else
            {
                ShoppingCart.Add(item);
            }
        }

        public void RemoveFromCart(string productId)
        {
            ShoppingCart.RemoveAll(i => i.ProductId == productId);
        }

        public decimal GetCartTotal()
        {
            return ShoppingCart.Sum(item => item.GetTotal());
        }

        public bool HasPermission(string permissionName, string resource, string action)
        {
            return Permissions.Any(p => 
                p.PermissionName == permissionName && 
                p.Resource == resource && 
                p.HasAction(action));
        }
